/** Get art for a theme, with auto-generated pattern/accent fallbacks */
export function getThemeArt(themeId: string): ThemeArt {
  const art = THEME_ART[themeId];
  if (!art) return {};

  // If theme has corner but missing pattern/accent, generate defaults
  if (art.cornerSvg && (!art.heroPatternSvg || !art.accentSvg)) {
    // Extract the primary color from the cornerSvg
    const colorMatch = art.cornerSvg.match(/#[0-9A-Fa-f]{6}/);
    const color = colorMatch ? colorMatch[0] : '#A3B18A';

    if (!art.heroPatternSvg) {
      art.heroPatternSvg = `<svg viewBox="0 0 50 50" xmlns="http://www.w3.org/2000/svg"><circle cx="25" cy="25" r="1" fill="${color}" opacity="0.12"/><circle cx="5" cy="5" r="0.5" fill="${color}" opacity="0.12"/><circle cx="45" cy="45" r="0.5" fill="${color}" opacity="0.12"/></svg>`;
    }
    if (!art.accentSvg) {
      art.accentSvg = `<svg viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg"><circle cx="50" cy="50" r="30" fill="none" stroke="${color}" stroke-width="1" opacity="0.15"/><circle cx="50" cy="50" r="20" fill="none" stroke="${color}" stroke-width="0.5" opacity="0.18"/></svg>`;
    }
  }

  return art;
}
